# Main application module

def calculate_total(items):
    # Calculate the total price of a list of items.
    total = 0.0
    for item in items:
        if 'price' in item:
            total += item['price']
    return total

def process_order(order_id, items):
    # Processes an order.
    total = calculate_total(items)
    return {
        'order_id': order_id,
        'total': total,
        'status': 'processed'
    }

def validate_item(item):
    # Simplified validation.
    return 'name' in item and 'price' in item

if __name__ == '__main__':
    test_items = [
        {'name': 'Item 1', 'price': 10.0},
        {'name': 'Item 2', 'price': 20.0}
    ]
    result = process_order('ORD-001', test_items)
    print(f"Order result: {result}")

    invalid_items = [
        {'name': 'Item 3', 'price': 30.0},
        {'name': 'Item 4'}
    ]
    result = process_order('ORD-002', invalid_items)
    print(f"Order result: {result}")

